INSERT INTO formations (id_formation, titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) SELECT gen_random_uuid(), v.* FROM (VALUES ('Optimisation pour les moteurs de recherche (SEO)', 'Formation sur les techniques d’optimisation SEO pour améliorer la visibilité et le positionnement sur les moteurs de recherche.', 15, 100000.00, 'entreprise', '2026-01-25', 30, '2026-01-14 12:37:32', '2026-02-18 23:44:04', NULL, E'--- OBJECTIFS ---\n• Comprendre les fondamentaux du SEO\n• Optimiser le contenu et la structure des pages web\n• Améliorer la visibilité et le trafic organique\n• Utiliser les outils SEO pour analyser et suivre les performances\n• Développer une stratégie digitale durable\n\n--- OBJECTIFS DÉTAILLÉS ---\nMaîtriser les techniques de référencement naturel, optimiser le contenu et la structure des sites web, utiliser les outils SEO pour analyser et améliorer les performances et développer une stratégie digitale efficace.\n\n--- PRÉREQUIS ---\nConnaissances de base en marketing digital ou gestion de site web.\n\n--- CONTENU ---\nModule 1 : Introduction au SEO et enjeux\nModule 2 : Optimisation technique des sites web\nModule 3 : Stratégies de contenu et mots-clés\nModule 4 : Netlinking et autorité de domaine\nModule 5 : Outils SEO et analyse des performances\nModule 6 : Mise en place d’une stratégie SEO durable\nModule 7 : Atelier pratique – Optimisation d’un site web\n\n--- NIVEAU ---\nTous niveaux\n\n--- PUBLIC ---\nResponsables marketing digital, webmasters, créateurs de contenu, consultants SEO, entrepreneurs souhaitant améliorer leur visibilité en ligne.\n\n--- MÉTHODES ---\nPrésentations interactives, démonstrations, ateliers pratiques, études de cas et simulations.\n\n--- SUPPORTS ---\nOutils SEO (Google Analytics, Google Search Console, SEMrush, Ahrefs), tableurs Excel, guides pratiques, modèles de plan SEO, supports PDF et slides.\n\n--- CERTIFICATION ---\nAttestation de participation remise par ISD Groupe', 'ba52f30c-c061-41b8-b0f7-afa6eca6fa76')) AS v(titre, description, duree, prix, categorie, date_debut, places_disponibles, created_at, updated_at, deleted_at, benefices, id_pays) WHERE NOT EXISTS (SELECT 1 FROM formations f WHERE f.titre = v.titre AND f.date_debut = v.date_debut::date);
